Rules.InvariantScript:
// revert to previous job entries & window mulls collections if the user cancels
If(
    !locLeadTestsSave,
    ClearCollect(
        colCdsJobEntries,
        colJobEntriesCancel
    );
    ClearCollect(
        colCdsJobs,
        colJobsCancel
    );
    ClearCollect(
        colAUDRecords,
        colAUDRecordsCancel
    );
);
// reset variables
UpdateContext(
    {
        locComponentExteriorInterior: Blank(),
        locComponentSelected: Blank(),
        locComponentIsCustomValue: false,
        locShowLeadTestSummary: false
    }
);

// save data to revert if changes cancelled
ClearCollect(
    colJobEntriesCancel,
    colCdsJobEntries
);
ClearCollect(
    colJobsCancel,
    colCdsJobs
);
ClearCollect(
    colAUDRecordsCancel,
    colAUDRecords
);
// reset variables
UpdateContext({locLeadTestsSave: false});

// set current job entry
Set(
    gblProjectSidebarItemCurrent,
    ThisItem
);
Set(
    gblRecordWindowMeasurement_Tech,
    LookUp(
        colCdsWindowMeasurements,
        'Window Measurement' = ThisItem.ID
    )
);
// reset controls
Reset(txt_LeadTest_Exterior__Swab);
Reset(txt_LeadTest_Exterior__Result);
Reset(txt_LeadTest_Interior__Swab);
Reset(txt_LeadTest_Interior__Result);

With(
    {
        varRecordWindowMeasurement: If(
            ThisItem.Category="Window Measurement",
            LookUp(
                colCdsWindowMeasurements,
                'Window Measurement'=ThisItem.ID
            ),
            Blank()
        )
    },
    Or(
        !IsBlank(varRecordWindowMeasurement.'Window Mull'.'Sequence Number'),
        !IsBlank(varRecordWindowMeasurement.'Lead Test: Exterior Result')
    )
)

/*
    wCompanyName: "Window Nation",
    wCompanyAddress: "8110 Maple Lawn Boulevard",
    wCompanyCityStateZip: "Fulton, MD, 20759",
    wCompanyPhone: "(443) 577-3165",
    wCompanyCertificate: "NAT-21505-3",
    wCompanyCertExpiry: "4/16/2025",
    wTestKitCompany: "Hybrivet",
    wTestKitType: "Lead Test Swabs",
    wTestKitCatalog: "PB-2M96"
*/

With({
    wCompanyName: "Window Nation",
    wCompanyAddress: "(shown only on pdf document)",
    wCompanyCityStateZip: "(shown only on pdf document)",
    wCompanyPhone: "(shown only on pdf document)",
    wCompanyCertificate: "(shown only on pdf document)",
    wCompanyCertExpiry: "(shown only on pdf document)",
    wTestKitCompany: "(shown only on pdf document)",
    wTestKitType: "(shown only on pdf document)",
    wTestKitCatalog: "(shown only on pdf document)"
},
